class Animal:
    def __init__(self, name):
        self.name = name

    def speak(self):
        return 'Some sound'

class Dog(Animal):
    pass

dog = Dog('Rex')
print(dog.name)
print(dog.speak())

class Animal:
    def __init__(self, name):
        self.name = name

class Dog(Animal):
    def __init__(self, name, breed):
        super().__init__(name)
        self.breed = breed

    def info(self):
        return f'{self.name} is a {self.breed}'

dog = Dog('Rex', 'Labrador')
print(dog.info())

class Animal:
    def speak(self):
        return 'Some sound'

class Dog(Animal):
    def speak(self):
        return 'Woof!'

class Cat(Animal):
    def speak(self):
        return 'Meow!'

animals = [Dog(), Cat()]
for a in animals:
    print(a.speak())
